#include <stdint.h>

#define M 32
#define N 32
#define K 32

static float A[M][K];
static float B[K][N];
static float C[M][N];

static void init(void) {
    for (int i = 0; i < M; i++)
        for (int k = 0; k < K; k++)
            A[i][k] = (float)((i * 7 + k) & 0xf);
    for (int k = 0; k < K; k++)
        for (int j = 0; j < N; j++)
            B[k][j] = (float)((k * 3 + j) & 0xf);
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N; j++)
            C[i][j] = 0.0f;
}

__attribute__((noinline))
static void gemm(void) {
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N; j++) {
            float acc = 0.0f;
            for (int k = 0; k < K; k++) {
                acc += A[i][k] * B[k][j];
            }
            C[i][j] = acc;
        }
    }
}

volatile float sink;

int main(void) {
    init();
    for (int rep = 0; rep < 4; rep++) {
        gemm();
        sink = C[0][0];
    }
    return 0;
}

